// 골격(타일/워프)은 자동 생성, NPC/대사/트리거/추가 맵(MAP_RIVAL_HOUSE 등)은 손편집 영역.
// 재생성 시 손편집된 데이터가 사라집니다 — git diff로 복원 필요.
#pragma once
#include "sprites.h"  // NPC_SPR_* enum 사용

// ─── 타일 종류 ─────────────────────────────────────────────────
// ' '  빈 땅/잔디 (이동 가능)
// '.'  길 (이동 가능)
// ';'  긴 풀 (야생 인카운터)
// '#'  벽/건물/나무 (통과 불가)
// '~'  물 (통과 불가, 비주얼)
// 'D'  문 (워프 타일)
// 's'  표지판
// 'N'  NPC 위치

// NpcDef.spriteId / TrainerDef.spriteId 는 sprites.h의 NpcSpriteId enum 인덱스.
//   0 MOM   1 OAK   2 BLUE        3 GRAMPS    4 NURSE    5 CLERK
//   6 GIRL  7 BRUNETTE   8 LITTLE_BOY  9 LITTLE_GIRL  10 FISHER
//   11 GENTLEMAN   12 POKE_BALL
// NpcDef.trigger: 대화 종료 시 emit할 이벤트
//   0 = 없음, 1 = STARTER_TRIGGER (연구소 오박사 → 스타터 선택)
struct NpcDef {
    int x, y;
    const wchar_t* lines[4];
    int spriteId = 0;       // 기본 0 = MOM
    int trigger  = 0;       // 기본 0 = 트리거 없음
};

struct TrainerDef {
    int x, y;
    int dir;
    int sightRange;
    const wchar_t* name;
    const wchar_t* preBattleText;
    int partyIds[3];
    int partyLevels[3];
    bool defeated;
    int spriteId = 11;       // OW 모양 — 기본 GENTLEMAN
    int introSpriteId = 0;   // 배틀 시작 시 풀바디 IntroSprite (0=OAK, 1=RIVAL, ...)
    bool isBoss = false;     // 체육관 관장(브록 등) 표시 — BOSS_BATTLE 트리거
};

struct WarpDef {
    int srcX, srcY;
    int destMap;
    int destX, destY;
};

struct EncounterEntry {
    int speciesId;
    int minLevel, maxLevel;
    int weight;
};

struct MapDef {
    int         id;
    int         mapW, mapH;   // 실제 맵 크기 (스텝 단위)
    const char* name;
    const wchar_t* nameW;
    const char* tiles[73];   // 최대 72행 + nullptr 지원
    NpcDef      npcs[8];
    int         numNpcs;
    TrainerDef  trainers[4];
    int         numTrainers;
    WarpDef     warps[12];
    int         numWarps;
    EncounterEntry encounters[6];
    int         numEncounters;
    int         northMap;
    int         southMap;
    int         northEntryX, northEntryY;
    int         southEntryX, southEntryY;
    const wchar_t* bgmFile;
};

