inline const SignDef* findSign(int mapId, int x, int y) {
    for (int i = 0; i < NUM_SIGNS; i++) {
        if (ALL_SIGNS[i].mapId == mapId &&
            ALL_SIGNS[i].x == x && ALL_SIGNS[i].y == y) {
            return &ALL_SIGNS[i];
        }
    }
    return nullptr;
}

// walkable: pokered Overworld_Coll 통과 atom(BL)을 가진 char만.
// 분류 근거: 각 char의 atom 4-tuple BL이 OVERWORLD_PASS={00,10,1b,20,21,23,2c,2d,2e,30,31,33,39,3c,3e,52,54,58,5b}에 속하는지.
// PT('!','$','%','(','1','@','H','J','K','^')는 BL=0x4e/0x32/0x14/0x1a/0x3a 등이라 모두 BLOCK.
// map-aware: 각 tileset의 char 의미가 달라서 mapId 로 dispatch
inline bool tileWalkable(char t, int mapId = 0) {
    // Viridian Forest (MAP_4) — forest tileset
    if (mapId == 4) {
        return t == ' ' || t == '!' || t == '*' || t == ',' || t == '-' || t == ';';
    }
    // 오버월드 도시/도로 (MAP_0,1,2,3,5) — v3 atom-based
    // pokered 충돌 분석:
    //   '<' [44,44,55,52]  BL=55=ledge atom → 남쪽 jump-down 절벽 (걷기 불가, isLedge에서 처리)
    //   '?' [44,44,60,60]  BL=60=passable → 일반 walkable 계단
    if (mapId >= 0 && mapId <= 5) {
        return t == ' ' || t == '!' || t == '%' || t == '&' || t == '(' ||
               t == '+' || t == '-' || t == '4' || t == ';' || t == '?' ||
               t == 'C' || t == 'D' || t == 'G' || t == 'M';
    }
    // PC + Mart (MAP_11..14) — pokecenter tileset
    if (mapId >= 11 && mapId <= 14) {
        return t == ' ' || t == '!' || t == '$' || t == '+' || t == '4' || t == 'B';
    }
    // Gate maps (MAP_15 Route2Gate, MAP_16 ForestNorthGate, MAP_17 ForestSouthGate) — gate tileset
    if (mapId == 15 || mapId == 16 || mapId == 17) {
        return t == ' ' || t == '!' || t == '*' || t == '+';
    }
    // Pewter Gym (MAP_8) — gym tileset (gen_pewter_gym_tiles.py)
    if (mapId == 8) {
        return t == '!' || t == '(' || t == '?';
    }
    // 실내 (reds_house, oaklab — MAP_6,7,9,10)
    return t == ' ' || t == 'f' || t == 'i' || t == 'u' || t == '+';
}
inline bool tileIsEncounter(char t) {
    return t == ';';
}
inline char getTile(const MapDef* m, int x, int y) {
    if (!m || x < 0 || x >= m->mapW || y < 0 || y >= m->mapH) return '#';
    if (!m->tiles[y]) return '#';
    int len = 0; while (m->tiles[y][len]) len++;
    if (x >= len) return ' ';
    return m->tiles[y][x];
}

inline bool tileIsDoor(char t) {
    return t == '!' || t == '#' || t == '(' || t == '1' || t == '@' || t == 'A' || t == 'B' || t == 'H' || t == 'I' || t == 'J' || t == 'K' || t == '^' || t == 'w';
}
